index fdef49e310f8..acf68fe07f7c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -841,6 +841,19 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
       Value *And = Builder.CreateAnd(X, Builder.CreateOr(MaskC, One));
       return new ICmpInst(ICmpInst::ICMP_NE, And, Zero);
     }
+    if (match(Src, m_Shr(m_Power2(C1), m_Value(X)))) {
+      // trunc (lshr/ashr C1, X) to i1 --> icmp eq X, log2(C1), where C1 is pow2
+      Constant *Log2C1 = ConstantInt::get(SrcTy, C1->exactLogBase2());
+      return new ICmpInst(ICmpInst::ICMP_EQ, X, Log2C1);
+    }
+    {
+      const APInt *C;
+      if (match(Src, m_Shr(m_APInt(C), m_Value(X))) && (*C + 1).isPowerOf2()) {
+        // trunc (lshr/ashr C, X) to i1 --> icmp ult X, log2(C+1), where C+1 is pow2
+        Constant *Log2C1 = ConstantInt::get(SrcTy, (*C + 1).exactLogBase2());
+        return new ICmpInst(ICmpInst::ICMP_ULT, X, Log2C1);
+      }
+    }

